arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0
  {
    //---------- Movement ----------
    moveTime+=1
    if moveTime>=45
    {
      xVel*=-1
      moveTime=irandom(5)
    }
    
    if throwTime<throwDelay
    {
      if x>oPlayer1.x
        image_xscale=-1
      else
        image_xscale=1
    }
    
    //---------- Throw hammer ----------
    throwTime+=1
    if throwTime>=throwDelay
    {
      if throwTime=throwDelay //change anim
        sprite_index=sHammerThrowerThrow
      else if throwTime=throwDelay+6 //Throw hammer
      {
        var tNewAttack;
        tNewAttack=instance_create(x-(4*image_xscale),y-24,oGravityBullet)
        tNewAttack.sprite_index=sHammerThrowerHammer
        if image_xscale=-1
          tNewAttack.image_xscale=-1
        tNewAttack.atkPower=atkPower
        tNewAttack.xVel=random_range(3,4)*image_xscale
        tNewAttack.yVel=-random_range(5,6)
        throwCycle+=1
        if throwCycle=6
        {
          if random(10)>3
          {
            y-=2
            yVel=-2.5
          }
          throwDelay=16
          throwCycle=0
        }
        else
          throwDelay=8
        sprite_index=sHammerThrowerWalk
        throwTime=0
      }
    }
    
    yVel+=0.2
    if isCollisionBottom(1)
      yVel=0
    if isCollisionLeft(1)
      xVel=runAcc
    if isCollisionRight(1)
      xVel=-runAcc
    if isCollisionSolid()
      y-=2
    
    moveTo(xVel,yVel)
    if y>room_height+24
      instance_destroy()
  }
  enemyStepEvent()
}
